mapper.select:
SELECT id, provider_id, provider_name, trigger_type, status,
       start_time, end_time, duration, channel_count,
       error_message, raw_content, created_at, updated_at
FROM m3u8_refresh_task
WHERE deleted = 0

    AND provider_name LIKE '%' || #{providerName} || '%'


    AND trigger_type = #{triggerType}


    AND status = #{status}


    AND created_at >= #{startTime}


    AND created_at <= #{endTime}

ORDER BY id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM m3u8_refresh_task
WHERE deleted = 0

    AND provider_name LIKE '%' || #{providerName} || '%'


    AND trigger_type = #{triggerType}


    AND status = #{status}


    AND created_at >= #{startTime}


    AND created_at <= #{endTime}
